    auto var_b = reaction::makeVar(b);
    auto var_c = reaction::makeVar(c);

    // 2. Create initial calculation (depends on a + b)
    auto calc = reaction::makeCalc([&]() {
        return var_a() + var_b();
    });

    // 3. Reset calculation with different dependencies (now depends on b + c)
    calc.reset([&]() {
        return var_b() + var_c();
    });

    // 4. Return result after reset
    return calc();
}

}  // namespace test_reaction

